local function isCarryingSurvivor()
    local char = LocalPlayer.Character
    if not char then return false end
    for _, v in ipairs(char:GetDescendants()) do
        if v:IsA("Weld") or v:IsA("Motor6D") or v:IsA("WeldConstraint") then
            local p1 = v.Part1 and v.Part1.Parent
            local p0 = v.Part0 and v.Part0.Parent
            if (p1 and Players:GetPlayerFromCharacter(p1) and p1 ~= char) or 
               (p0 and Players:GetPlayerFromCharacter(p0) and p0 ~= char) then
                return true
            end
        end
    end
    return false
end

local isBusyWithSurvivor = false
local hasCarryStarted = false
local lastCarryStartTime = 0
local wasAutoAttackEnabled = false
local wasBrutalAttackEnabled = false
local wasOneHitEnabled = false
local kebalTwistActive = false
local godModeConnection = nil
local isShootingTwist = false
local autoParryActive = false
local autoParryDistance = 10
local parryNoCooldownActive = false
local advancedRemoteSpyActive = false


local lastAssetLoadReset = tick()

-- Prevent infinite yields on VM and Melee by proactively creating dummy assets when needed
task.spawn(function()
    -- Prevent infinite yields on ReplicatedStorage.Animations:WaitForChild("Melee")
    task.spawn(function()
        local animations = ReplicatedStorage:WaitForChild("Animations")
        while true do
            if tick() - lastAssetLoadReset > 6 then
                if not animations:FindFirstChild("Melee") then
                    pcall(function()
                        local melee = Instance.new("Animation")
                        melee.Name = "Melee"
                        melee.AnimationId = "rbxassetid://0"
                        melee.Parent = animations
                        warn("[VD] Created dummy Melee animation due to timeout")
                    end)
                end
            end
            task.wait(1)
        end
    end)

    -- Prevent infinite yields on Workspace.Camera:WaitForChild("VM")
    task.spawn(function()
        local camera = workspace.CurrentCamera or workspace:WaitForChild("Camera")
        while true do
            if tick() - lastAssetLoadReset > 6 then
                if not camera:FindFirstChild("VM") then
                    pcall(function()
                        local vm = Instance.new("Model")
                        vm.Name = "VM"
                        local hum = Instance.new("Humanoid", vm)
                        Instance.new("Animator", hum)
                        vm.Parent = camera
                        warn("[VD] Created dummy VM model due to timeout")
                    end)
                end
            end
            task.wait(1)
        end
    end)
end)

-- Auto-cleanup dummy VM and Melee when the game loads the real ones
task.spawn(function()
    local animations = ReplicatedStorage:WaitForChild("Animations")
    animations.ChildAdded:Connect(function(child)
        if child.Name == "Melee" and child:IsA("Animation") and child.AnimationId ~= "rbxassetid://0" and child.AnimationId ~= "" then
            pcall(function()
                for _, v in ipairs(animations:GetChildren()) do
                    if v.Name == "Melee" and (v.AnimationId == "rbxassetid://0" or v.AnimationId == "") then
                        v:Destroy()
                        warn("[VD] Destroyed dummy Melee animation as real one loaded")
                    end
                end
            end)
        end
    end)

    local camera = workspace.CurrentCamera or workspace:WaitForChild("Camera")
    camera.ChildAdded:Connect(function(child)
        if child.Name == "VM" and child:IsA("Model") and (child:FindFirstChild("Head") or child:FindFirstChild("Torso") or child:FindFirstChildWhichIsA("BasePart")) then
            pcall(function()
                for _, v in ipairs(camera:GetChildren()) do
                    if v.Name == "VM" and not v:FindFirstChild("Head") and not v:FindFirstChild("Torso") and not v:FindFirstChildWhichIsA("BasePart") then
                        v:Destroy()
                        warn("[VD] Destroyed dummy VM model as real one loaded")
                    end
                end
            end)
        end
    end)
end)

local oldFireServer
if hookfunction and checkcaller then
    local dummyEvent = Instance.new("RemoteEvent")
    oldFireServer = hookfunction(dummyEvent.FireServer, newcclosure(function(self, ...)
        if not checkcaller() then
            local success, name = pcall(function() return self.Name end)
            if success then
                local args = {...}
                
                if name == "Activate" and _G.VDInfFlashlight then
                    local s2, pName = pcall(function() return self.Parent.Name end)
                    if s2 and pName == "Flashlight" then
                        if args[2] == true then
                            _G.VDFlashlightIntendedState = true
                        elseif args[2] == false then
                            _G.VDFlashlightIntendedState = false
                        end
                    end
                end
                
                if name == "CarrySurvivorEvent" or name == "HookEvent" or name == "HookPhase" or name == "PlayAnimation" then
                    LogExploit("[VD DEBUG] Carry/Hook Event detected: " .. tostring(name) .. " autoAttackActive: " .. tostring(autoAttackActive) .. " isBusyWithSurvivor: " .. tostring(isBusyWithSurvivor))
                    if (autoAttackActive or _G.VDBrutalAttack or _G.VDOneHitAttack or killAllActive) and not isBusyWithSurvivor then
                        isBusyWithSurvivor = true
                        hasCarryStarted = false
                        lastCarryStartTime = tick()
                        if autoAttackActive then
                            wasAutoAttackEnabled = true
                            autoAttackActive = false
                        end
                        if _G.VDBrutalAttack then
                            wasBrutalAttackEnabled = true
                            _G.VDBrutalAttack = false
                        end
                        if _G.VDOneHitAttack then
                            wasOneHitEnabled = true
                            _G.VDOneHitAttack = false
                        end
                        if killAllActive then
                            wasKillAllEnabled = true
                            killAllActive = false
                        end
                        task.spawn(function()
                            if wasAutoAttackEnabled then 
                                UICommunicationEvent:Fire("SetAutoAttackState", false, true) 
                                Notify("Auto Attack", "Paused (Carrying)", 2)
                            end
                            if wasBrutalAttackEnabled then 
                                UICommunicationEvent:Fire("SetBrutalAttackState", false, true) 
                                Notify("Brutal Attack", "Paused (Carrying)", 2)
                            end
                            if wasOneHitEnabled then 
                                UICommunicationEvent:Fire("SetOneHitAttackState", false, true)
                                Notify("One Hit Attack", "Paused (Carrying)", 2)
                            end
                            if wasKillAllEnabled then
                                UICommunicationEvent:Fire("SetKillAllState", false, true)
                                Notify("Kill All", "Paused (Carrying)", 2)
                            end
                        end)
                    end
                elseif name == "HookEventsucceess" or name == "HookCommit" or name == "HookReject" or name == "UnhookSuccess" or name == "UnHookEvent" then
                    LogExploit("[VD DEBUG] Drop/Hook Success Event detected: " .. tostring(name) .. " wasAutoAttackEnabled: " .. tostring(wasAutoAttackEnabled) .. " wasBrutalAttackEnabled: " .. tostring(wasBrutalAttackEnabled))
                    if wasAutoAttackEnabled or wasBrutalAttackEnabled or wasOneHitEnabled or wasKillAllEnabled then
                        local hadAuto = wasAutoAttackEnabled
                        local hadBrutal = wasBrutalAttackEnabled
                        local hadOneHit = wasOneHitEnabled
                        local hadKillAll = wasKillAllEnabled
                        wasAutoAttackEnabled = false
                        wasBrutalAttackEnabled = false
                        wasOneHitEnabled = false
                        wasKillAllEnabled = false
                        isBusyWithSurvivor = false 
                        hasCarryStarted = false
                        task.spawn(function()
                            if hadAuto then 
                                UICommunicationEvent:Fire("SetAutoAttackState", true, true) 
                                Notify("Auto Attack", "Resumed", 2)
                            end
                            if hadBrutal then 
                                UICommunicationEvent:Fire("SetBrutalAttackState", true, true) 
                                Notify("Brutal Attack", "Resumed", 2)
                            end
                            if hadOneHit then 
                                UICommunicationEvent:Fire("SetOneHitAttackState", true, true)
                                Notify("One Hit Attack", "Resumed", 2)
                            end
                            if hadKillAll then
                                UICommunicationEvent:Fire("SetKillAllState", true, true)
                                Notify("Kill All", "Resumed", 2)
                            end
                        end)
                        task.delay(1.5, function()
                            if hadAuto then autoAttackActive = true end
                            if hadBrutal then _G.VDBrutalAttack = true end
                            if hadOneHit then _G.VDOneHitAttack = true end
                            if hadKillAll then killAllActive = true end
                            LogExploit("[VD DEBUG] Attacks set back to true")
                        end)
                    else
                        task.delay(1.5, function() isBusyWithSurvivor = false end)
                    end
                elseif self.Parent and self.Parent.Name == "Twist of Fate" then
                    if name == "Fire" and aimbotActive then
                        local myChar = LocalPlayer.Character
                        if myChar and myChar:FindFirstChild("HumanoidRootPart") then
                            local myPos = myChar.HumanoidRootPart.Position
                            local closestPlayer = nil
                            local shortestDistance = math.huge
                            for _, p in ipairs(Players:GetPlayers()) do
                                if p ~= LocalPlayer and p.Character and p.Character:FindFirstChild("HumanoidRootPart") and p.Character:FindFirstChild("Humanoid") and p.Character.Humanoid.Health > 0 then
                                    if p:GetAttribute("Role") == "Killer" then
                                        local pos = p.Character.HumanoidRootPart.Position
                                        local dist = (pos - myPos).Magnitude
                                        if dist < shortestDistance then
                                            shortestDistance = dist
                                            closestPlayer = p
                                        end
                                    end
                                end
                            end
                            if closestPlayer and closestPlayer.Character and closestPlayer.Character:FindFirstChild("HumanoidRootPart") then
                                local targetPos = closestPlayer.Character.HumanoidRootPart.Position
                                
                                local gunPos = myPos
                                local gun = myChar:FindFirstChild("Twist of Fate")
                                if gun and gun:FindFirstChild("Handle") then gunPos = gun.Handle.Position end
                                
                                local direction = (targetPos - gunPos).Unit
                                args[2] = direction
                                
                                task.spawn(function()
                                    for i = 1, 9 do
                                        oldFireServer(self, unpack(args))
                                        task.wait(0.05)
                                    end
                                end)
                            end
                        end
                    end
                end
                
                if kebalTwistActive then
                    local lowerName = name:lower()
                    if lowerName:find("fail") or lowerName:find("explode") or lowerName:find("damage") or lowerName:find("knock") then
                        print("[VD DEBUG] Blocked suspected Twist of Fate remote:", name, "Parent:", self.Parent and self.Parent.Name)
                        return
                    end
                end
            end
        end
        return oldFireServer(self, ...)
    end))
end

MakeToggle("AutoParry", "Auto Parry (Parrying Dagger)", function(val)
    autoParryActive = val
    if val then
