killAllToggleObj = MakeToggle("KillAll", "Kill All (Teleport & One Hit)", function(val)
    if not isBusyWithSurvivor then
        killAllActive = val
    else
        wasKillAllEnabled = val
    end
    if val then
        task.spawn(function()
            while killAllActive or wasKillAllEnabled do
                task.wait(0.2)
                if not killAllActive and wasKillAllEnabled then
                    task.wait(0.5)
                    continue
                end
                pcall(function()
                    if isBusyWithSurvivor or isCarryingSurvivor() then return end
                    local myChar = LocalPlayer.Character
                    local myRoot = myChar and myChar:FindFirstChild("HumanoidRootPart")
                    if not myRoot then return end
                    
                    -- Collect all valid targets
                    local targets = {}
                    for _, p in ipairs(Players:GetPlayers()) do
                        if p ~= LocalPlayer and p.Team ~= LocalPlayer.Team and p.Character then
                            local root = p.Character:FindFirstChild("HumanoidRootPart")
                            local hum = p.Character:FindFirstChild("Humanoid")
                            local isDowned = hum and (hum.WalkSpeed < 8 or hum.PlatformStand)
                            if root and hum and hum.Health > 0 and not isDowned then
                                table.insert(targets, p.Character)
                            end
                        end
                    end
                    
                    -- Teleport and attack each target one by one
                    for _, char in ipairs(targets) do
                        if not killAllActive then break end
                        if isBusyWithSurvivor or isCarryingSurvivor() then break end
                        
                        local root = char:FindFirstChild("HumanoidRootPart")
                        local hum = char:FindFirstChild("Humanoid")
                        
                        local checkCount = 0
                        while root and hum and hum.Health > 0 and killAllActive and not (hum.WalkSpeed < 8 or hum.PlatformStand) and not isBusyWithSurvivor and not isCarryingSurvivor() and checkCount < 30 do
                            checkCount = checkCount + 1
                            
                            -- Teleport close behind them (matching BrutalAutoAttack)
                            myRoot.CFrame = root.CFrame * CFrame.new(0, 0, 3)
                            
                            -- Activating weapon / remote spam
                            local tool = myChar:FindFirstChildOfClass("Tool")
                            if tool then
                                tool:Activate()
                            else
                                local remotes = ReplicatedStorage:FindFirstChild("Remotes")
                                local attacks = remotes and remotes:FindFirstChild("Attacks")
                                local atk = attacks and (attacks:FindFirstChild("BasicAttack") or attacks:FindFirstChild("Attack"))
                                if atk then
                                    atk:FireServer()
                                end
                            end
                            task.wait() -- Extreme speed spam
                        end
                        task.wait(0.05)
                    end
                end)
            end
        end)
    end
end)

task.spawn(function()
    while true do
        task.wait(0.1) -- Faster loop for responsive Auto Attack
        if isBusyWithSurvivor then
            if not hasCarryStarted then
                if isCarryingSurvivor() then
                    hasCarryStarted = true
                    LogExploit("[VD DEBUG] Carry successfully started (Weld detected).")
                end
            else
                if not isCarryingSurvivor() then
                    LogExploit("[VD DEBUG] Carry interrupted (Weld lost). Instantly resetting state.")
                    isBusyWithSurvivor = false
                    hasCarryStarted = false
                    if wasAutoAttackEnabled then
                        wasAutoAttackEnabled = false
                        autoAttackActive = true
                        task.spawn(function()
                            UICommunicationEvent:Fire("SetAutoAttackState", true, true)
                            Notify("Auto Attack", "Resumed", 2)
                        end)
                    end
                    if wasBrutalAttackEnabled then
                        wasBrutalAttackEnabled = false
                        _G.VDBrutalAttack = true
                        task.spawn(function()
                            UICommunicationEvent:Fire("SetBrutalAttackState", true, true)
                            Notify("Brutal Attack", "Resumed", 2)
                        end)
                    end
                    if wasOneHitEnabled then
                        wasOneHitEnabled = false
                        _G.VDOneHitAttack = true
                        task.spawn(function()
                            UICommunicationEvent:Fire("SetOneHitAttackState", true, true)
                            Notify("One Hit Attack", "Resumed", 2)
                        end)
                    end
                    if wasKillAllEnabled then
                        wasKillAllEnabled = false
                        killAllActive = true
                        task.spawn(function()
                            UICommunicationEvent:Fire("SetKillAllState", true, true)
                            Notify("Kill All", "Resumed", 2)
                        end)
                    end
                end
            end
            
            if not hasCarryStarted and (tick() - lastCarryStartTime > 4) then
                LogExploit("[VD DEBUG] Failsafe triggered: No survivor weld found. Resetting state.")
                isBusyWithSurvivor = false
                hasCarryStarted = false
                if wasAutoAttackEnabled then
                    wasAutoAttackEnabled = false
                    autoAttackActive = true
                    task.spawn(function()
                        UICommunicationEvent:Fire("SetAutoAttackState", true, true)
                        Notify("Auto Attack", "Resumed (Failsafe)", 2)
                    end)
                end
                if wasBrutalAttackEnabled then
                    wasBrutalAttackEnabled = false
                    _G.VDBrutalAttack = true
                    task.spawn(function()
                        UICommunicationEvent:Fire("SetBrutalAttackState", true, true)
                        Notify("Brutal Attack", "Resumed (Failsafe)", 2)
                    end)
                end
                if wasOneHitEnabled then
                    wasOneHitEnabled = false
                    _G.VDOneHitAttack = true
                    task.spawn(function()
                        UICommunicationEvent:Fire("SetOneHitAttackState", true, true)
                        Notify("One Hit Attack", "Resumed (Failsafe)", 2)
                    end)
                end
                if wasKillAllEnabled then
                    wasKillAllEnabled = false
                    killAllActive = true
                    task.spawn(function()
                        UICommunicationEvent:Fire("SetKillAllState", true, true)
                        Notify("Kill All", "Resumed (Failsafe)", 2)
                    end)
                end
            end
        end
        if autoAttackActive then
            pcall(function()
                if isBusyWithSurvivor or isCarryingSurvivor() then return end
                local myRoot = LocalPlayer.Character and getRoot(LocalPlayer.Character)
                if not myRoot then return end
                local targetInRange = false
                for _, p in ipairs(Players:GetPlayers()) do
                    if p ~= LocalPlayer and p.Character and getRoot(p.Character) then
                        if p.Team ~= LocalPlayer.Team then
                            local hum = p.Character:FindFirstChildOfClass("Humanoid")
                            local isDowned = hum and (hum.WalkSpeed < 8 or hum.PlatformStand)
                            if not isDowned then
                                local d = (getRoot(p.Character).Position - myRoot.Position).Magnitude
                                if d <= 5 then
                                    targetInRange = true
                                    break
                                end
                            end
                        end
                    end
                end
                if targetInRange then
                    local remotes = ReplicatedStorage:FindFirstChild("Remotes")
                    if remotes then
                        local attacks = remotes:FindFirstChild("Attacks")
                        if attacks then
                            local atk = attacks:FindFirstChild("BasicAttack") or attacks:FindFirstChild("Attack")
                            if atk then 
                                atk:FireServer() 
                                task.wait(3.5) -- Normal attack delay so it's safe and not spammy
                            end
                        end
                    end
                end
            end)
        end
    end
end)

