LocalPlayer.CharacterAdded:Connect(function()
    lastAssetLoadReset = tick()
    -- Reset/destroy previous round's dummy VM and Melee to let the game load the new round's real assets first
    pcall(function()
        local oldVM = workspace.CurrentCamera:FindFirstChild("VM")
        if oldVM and not oldVM:FindFirstChild("Head") and not oldVM:FindFirstChild("Torso") and not oldVM:FindFirstChildWhichIsA("BasePart") then 
            oldVM:Destroy() 
        end
        
        local anims = ReplicatedStorage:FindFirstChild("Animations")
        local oldMelee = anims and anims:FindFirstChild("Melee")
        if oldMelee and (oldMelee.AnimationId == "rbxassetid://0" or oldMelee.AnimationId == "") then 
            oldMelee:Destroy() 
        end
    end)

    task.delay(1.5, function()
        RefreshAllESP()
        pcall(function() Notify("Auto Refresh", "Map loaded, ESP Refreshed!", 2) end)
    end)
end)

