    for _, plr in pairs(Players:GetPlayers()) do
        pcall(function()
            local char = plr.Character
            if char then
            end
        end)
    end
    if playerAddedConnection then
        playerAddedConnection:Disconnect()
        playerAddedConnection = nil
    end
end
