	}
	function Network.RetainPart(part)
		if part:IsA("BasePart") and part:IsDescendantOf(Workspace) then
			table.insert(Network.BaseParts, part)
			part.CustomPhysicalProperties = PhysicalProperties.new(0, 0, 0, 0, 0)
			part.CanCollide = false
		end
	end
end
function EnableNetwork()
	if NetworkConnection then return end
	NetworkConnection = RunService.Heartbeat:Connect(function()
		pcall(function()
			sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge)
		end)
	end)
end
function DisableNetwork()
	if NetworkConnection then
		NetworkConnection:Disconnect()
		NetworkConnection = nil
	end
end
function hasHumanoidAncestor(v)
	local p = v.Parent
	while p and p ~= Workspace do
		if p:FindFirstChildOfClass("Humanoid") then
			return true
		end
		p = p.Parent
	end
	return false
end

function isPlayerOrAccessory(v)
	local p = v
	while p and p ~= Workspace do
		if p:IsA("Model") then
			if game:GetService("Players"):GetPlayerFromCharacter(p) then
				return true
			end
			if game:GetService("Players"):FindFirstChild(p.Name) then
				return true
			end
		end
		p = p.Parent
	end
	return false
end

function ForcePart(v)
	if v:IsA("BasePart") 
	and not v.Anchored 
	and not hasHumanoidAncestor(v) then

		for _, x in ipairs(v:GetChildren()) do
			if x:IsA("BodyMover") or x:IsA("RocketPropulsion") then
				x:Destroy()
			end
		end

		if v:FindFirstChild("Attachment") then pcall(function() v:FindFirstChild("Attachment"):Destroy() end) end
		if v:FindFirstChild("AlignPosition") then pcall(function() v:FindFirstChild("AlignPosition"):Destroy() end) end
		if v:FindFirstChild("Torque") then pcall(function() v:FindFirstChild("Torque"):Destroy() end) end
		if v:FindFirstChild("BringAttachment") then pcall(function() v:FindFirstChild("BringAttachment"):Destroy() end) end
		if v:FindFirstChild("BringAlign") then pcall(function() v:FindFirstChild("BringAlign"):Destroy() end) end
		if v:FindFirstChild("BringTorque") then pcall(function() v:FindFirstChild("BringTorque"):Destroy() end) end

		v.CanCollide = false
		v.CanTouch = false
		v.CanQuery = false
		v.Massless = true
		pcall(function() v.AssemblyLinearVelocity = Vector3.new(0, 50, 0) end)
		local Torque = Instance.new("Torque", v)
		Torque.Torque = Vector3.new(100000, 100000, 100000)
		local AlignPosition = Instance.new("AlignPosition", v)
		local Attachment2 = Instance.new("Attachment", v)
		Torque.Attachment0 = Attachment2
		AlignPosition.MaxForce = math.huge
		AlignPosition.MaxVelocity = math.huge
		AlignPosition.Responsiveness = 200
		AlignPosition.Attachment0 = Attachment2
		AlignPosition.Attachment1 = Attachment1
		broughtParts[v] = true
		print("[LOG] Berhasil menarik part: " .. tostring(v.Name))
	end
end
function YeetPart(v)
	if v:IsA("BasePart") then
		task.spawn(function()
			pcall(function()
				pcall(function() sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge) end)
				pcall(function() v:BreakJoints() end)
				v.CanCollide = false
				v.Anchored = false
				v.CFrame = CFrame.new(99999, 9999, 99999)
				v.AssemblyLinearVelocity = Vector3.new(0, 50000, 0)
				task.wait(0.05)
				v:Destroy()
			end)
		end)
	end
end
function OneTimeUnanchor()
	if _G.JSY_BringUnanchorCooldown then return end
	_G.JSY_BringUnanchorCooldown = true

	task.spawn(function()
		local startTime = tick()

		while tick() - startTime < 1 do
			for _, obj in pairs(Workspace:GetDescendants()) do
				if obj:IsA("RopeConstraint") then
					local part0 = obj.Attachment0 and obj.Attachment0.Parent
					local part1 = obj.Attachment1 and obj.Attachment1.Parent
					pcall(function() obj:Destroy() end)
					if part0 and part0:IsA("BasePart") then part0.Anchored = false end
					if part1 and part1:IsA("BasePart") then part1.Anchored = false end
				end
			end

			for _, part in pairs(Workspace:GetDescendants()) do
				if part:IsA("BasePart") and not part.Anchored and not hasHumanoidAncestor(part) then
					part.AssemblyLinearVelocity = Vector3.new(
						math.random(-50, 50),
						math.random(20, 100),
						math.random(-50, 50)
					)
				end
			end

			task.wait(0.2)
		end

		getgenv().UnanchorCooldown = false
		_G.JSY_BringUnanchorCooldown = false
	end)
end
function yeetAllParts()
    if blackHoleActive then
        blackHoleActive = false
        setButtonActive(BringPartBtn, false)
        if DescendantAddedConnection then
            DescendantAddedConnection:Disconnect()
            DescendantAddedConnection = nil
        end
    end
    if plistSendPartTarget then
        stopPlistSendPart()
    end
    if scannerBroughtPart then
        StopScannerBring()
    end
    EnableNetwork()
    local partsToYeet = scanParts()
    if #partsToYeet > 0 then
        task.spawn(function()
            for _, part in ipairs(partsToYeet) do
                task.spawn(function()
                    YeetPart(part)
                end)
            end
        end)
    end
end
function GetAllPartsRecursive(parent)
	local parts = {}
	for _, obj in ipairs(parent:GetChildren()) do
		if obj:IsA("BasePart") then
			table.insert(parts, obj)
		elseif obj:IsA("Folder") or obj:IsA("Model") then
			for _, childPart in ipairs(GetAllPartsRecursive(obj)) do
				table.insert(parts, childPart)
			end
		end
	end
	return parts
end
function breakPartConstraints(v)
	if not v or not v.Parent then return end
	pcall(function() v:BreakJoints() end)
	for _, child in ipairs(v:GetChildren()) do
		if child:IsA("Constraint") or child:IsA("Weld") or child:IsA("WeldConstraint") or child:IsA("JointInstance") then
			pcall(function() child:Destroy() end)
		end
	end
	local targetAttachments = {}
	for _, child in ipairs(v:GetChildren()) do
		if child:IsA("Attachment") then
			targetAttachments[child] = true
		end
	end
	for _, obj in ipairs(allConstraints) do
		if obj and obj.Parent then
			local isConnected = false
			pcall(function()
				if targetAttachments[obj.Attachment0] or targetAttachments[obj.Attachment1] or obj:IsDescendantOf(v) then
					isConnected = true
				end
			end)
			pcall(function()
				if obj:IsA("Weld") or obj:IsA("WeldConstraint") or obj:IsA("JointInstance") then
					if obj.Part0 == v or obj.Part1 == v then
						isConnected = true
					end
				end
			end)
			if isConnected then
				pcall(function() obj:Destroy() end)
			end
		end
	end
end
function toggleBringPart(state)
	if state == nil then
		blackHoleActive = not blackHoleActive
	else
		blackHoleActive = state
	end
	if blackHoleActive then
		setButtonActive(BringPartBtn, true)
		if MiniBringBtn then
            MiniBringBtn.Text = "Bring Part: ON"
            MiniBringBtn.TextColor3 = Color3.fromRGB(255, 255, 255)
        end
		EnableNetwork()
		pcall(function() 
            settings().Physics.AllowSleep = false 
            settings().Physics.PhysicsEnvironmentalThrottle = Enum.EnviromentalPhysicsThrottle.Disabled
        end)

		character = LocalPlayer.Character or LocalPlayer.CharacterAdded:Wait()
		humanoidRootPart = character:WaitForChild("HumanoidRootPart")
		head = character:WaitForChild("Head")
		local hum = character:FindFirstChildOfClass("Humanoid")
		if hum then
			pcall(function() hum:SetStateEnabled(Enum.HumanoidStateType.Seated, false) end)
		end
		broughtParts = {}

		OneTimeUnanchor()

		for _, v in ipairs(GetAllPartsRecursive(Workspace)) do
			ForcePart(v)
		end

		DescendantAddedConnection = Workspace.DescendantAdded:Connect(function(v)
			if blackHoleActive and v:IsA("BasePart") then
				ForcePart(v)
			end
		end)

		task.spawn(function()
			while blackHoleActive and RunService.RenderStepped:Wait() do
				if head then
					Attachment1.WorldCFrame = head.CFrame * CFrame.new(0, 10, 0)
				else
					if humanoidRootPart then
						Attachment1.WorldCFrame = humanoidRootPart.CFrame * CFrame.new(0, 10, 0)
					end
				end
			end
		end)
	else
		setButtonActive(BringPartBtn, false)
        if MiniBringBtn then
            MiniBringBtn.Text = "Bring Part: OFF"
            MiniBringBtn.TextColor3 = Color3.fromRGB(255, 50, 50)
        end
		DisableNetwork()
        if DescendantAddedConnection then
            DescendantAddedConnection:Disconnect()
            DescendantAddedConnection = nil
        end
        if broughtParts then
            for part, _ in pairs(broughtParts) do
                if part and part.Parent then
                    if part:FindFirstChild("Attachment") then pcall(function() part:FindFirstChild("Attachment"):Destroy() end) end
                    if part:FindFirstChild("AlignPosition") then pcall(function() part:FindFirstChild("AlignPosition"):Destroy() end) end
                    if part:FindFirstChild("Torque") then pcall(function() part:FindFirstChild("Torque"):Destroy() end) end
                end
            end
            broughtParts = {}
        end
		pcall(function() 
            settings().Physics.AllowSleep = true 
            settings().Physics.PhysicsEnvironmentalThrottle = Enum.EnviromentalPhysicsThrottle.DefaultAuto
        end)
		if DescendantAddedConnection then
			DescendantAddedConnection:Disconnect()
			DescendantAddedConnection = nil
		end
		for _, v in ipairs(Workspace:GetDescendants()) do
			if v:IsA("BasePart") then
				if broughtParts[v] then
					pcall(function()
						if v:FindFirstChild("Torque") then v:FindFirstChild("Torque"):Destroy() end
						if v:FindFirstChild("AlignPosition") then v:FindFirstChild("AlignPosition"):Destroy() end
						if v:FindFirstChild("Attachment") then v:FindFirstChild("Attachment"):Destroy() end
					end)
				end
			end
		end
		local hum = character and character:FindFirstChildOfClass("Humanoid")
		if hum then
			pcall(function() 
				if not flying then
					hum:SetStateEnabled(Enum.HumanoidStateType.Seated, true) 
					hum:ChangeState(Enum.HumanoidStateType.Running)
				end
			end)
		end
		local rootPart = character and (character:FindFirstChild("HumanoidRootPart") or character:FindFirstChild("Torso"))
		if rootPart then
			pcall(function()
				rootPart.AssemblyLinearVelocity = Vector3.zero
				rootPart.AssemblyAngularVelocity = Vector3.zero
			end)
		end
		broughtParts = {}
	end
end
BringPartBtn.MouseButton1Click:Connect(function()
    toggleBringPart()
end)

SwimBtn = createButton("", "Swim")
SwimBtn.Name = "SwimBtn"
local swimming = false
local oldgrav = workspace.Gravity
local swimbeat = nil
local gravReset = nil
function toggleSwim()
    swimming = not swimming
    setButtonActive(SwimBtn, swimming)
    local char = Player.Character
    if not char then return end
    local Humanoid = char:FindFirstChildWhichIsA("Humanoid")
    local root = char:FindFirstChild("HumanoidRootPart")
    if not Humanoid or not root then return end
    if swimming then
        oldgrav = workspace.Gravity
        workspace.Gravity = 0
        local swimDied = function()
            workspace.Gravity = oldgrav
            swimming = false
            setButtonActive(SwimBtn, false)
        end
        gravReset = Humanoid.Died:Connect(swimDied)
        local enums = Enum.HumanoidStateType:GetEnumItems()
        table.remove(enums, table.find(enums, Enum.HumanoidStateType.None))
        for i, v in pairs(enums) do
            Humanoid:SetStateEnabled(v, false)
        end
        Humanoid:ChangeState(Enum.HumanoidStateType.Swimming)
        swimbeat = RunService.Heartbeat:Connect(function()
            pcall(function()
                root.Velocity = ((Humanoid.MoveDirection ~= Vector3.new() or UserInputService:IsKeyDown(Enum.KeyCode.Space)) and root.Velocity or Vector3.new())
            end)
        end)
    else
        workspace.Gravity = oldgrav
        if gravReset then gravReset:Disconnect() end
        if swimbeat then swimbeat:Disconnect() swimbeat = nil end
        local enums = Enum.HumanoidStateType:GetEnumItems()
        table.remove(enums, table.find(enums, Enum.HumanoidStateType.None))
        for i, v in pairs(enums) do
            Humanoid:SetStateEnabled(v, true)
        end
    end
end
SwimBtn.MouseButton1Click:Connect(toggleSwim)

XRayBtn = createButton("", "XRay")
XRayBtn.Name = "XRayBtn"
local xrayEnabled = false
function toggleXRay(state)
    if state == nil then
        xrayEnabled = not xrayEnabled
    else
        xrayEnabled = state
    end
    setButtonActive(XRayBtn, xrayEnabled)
    if MiniXRayBtn then
        MiniXRayBtn.Text = "X-Ray: " .. (xrayEnabled and "ON" or "OFF")
        MiniXRayBtn.TextColor3 = xrayEnabled and Color3.fromRGB(255, 255, 255) or Color3.fromRGB(255, 50, 50)
    end
    for _, v in pairs(workspace:GetDescendants()) do
        if v:IsA("BasePart") then
            local p = v.Parent
            local pp = p and p.Parent
            local isChar = (p and p:FindFirstChildWhichIsA("Humanoid")) or (pp and pp:FindFirstChildWhichIsA("Humanoid"))
            if not isChar then
                v.LocalTransparencyModifier = xrayEnabled and 0.5 or 0
            end
        elseif v:IsA("Decal") or v:IsA("Texture") then
            if xrayEnabled then
                if not v:GetAttribute("OrigTrans") then
                    v:SetAttribute("OrigTrans", v.Transparency)
                end
                v.Transparency = 0.5
            else
                if v:GetAttribute("OrigTrans") then
                    v.Transparency = v:GetAttribute("OrigTrans")
                    v:SetAttribute("OrigTrans", nil)
                end
            end
        end
    end
end
XRayBtn.MouseButton1Click:Connect(toggleXRay)

