loopSendPartV2Active = false
local loopSendPartV2Thread = nil

function toggleLoopSendPartV2()
    loopSendPartV2Active = not loopSendPartV2Active
    setButtonActive(LoopSendPartV2Btn, loopSendPartV2Active)
    updateLoopSendPartV2Label()
    
    if loopSendPartV2Active then
        if loopSendPartActive then
            toggleLoopSendPart()
        end
        
        local tgtName = LoopSendPartBox.Text
        local target = findPlayerByQuery(tgtName)
        if target then
            LoopSendPartBox.PlaceholderText = "Target: " .. target.Name
            
            plistSendPartTarget = nil
            toggleBringPart(true)
            
            task.delay(0.5, function()
                if loopSendPartV2Active then
                    plistSendPartTarget = target
                end
            end)
            
            if loopSendPartV2Thread then pcall(task.cancel, loopSendPartV2Thread) end
            
            loopSendPartV2Thread = task.spawn(function()
                while loopSendPartV2Active do
                    local freshTarget = findPlayerByQuery(LoopSendPartBox.Text)
                    if plistSendPartTarget then
                        if freshTarget then
                            plistSendPartTarget = freshTarget
                        end
                    end
                    
                    loopSendPartOffset = CFrame.new(0, 0, 0)
                    task.wait(0.2)
                end
            end)
        else
            loopSendPartV2Active = false
            setButtonActive(LoopSendPartV2Btn, false)
            updateLoopSendPartV2Label()
            LoopSendPartBox.Text = ""
            LoopSendPartBox.PlaceholderText = "Player Not Found!"
            task.delay(1.5, function() LoopSendPartBox.PlaceholderText = "Username" end)
        end
    else
        if loopSendPartV2Thread then
            pcall(task.cancel, loopSendPartV2Thread)
            loopSendPartV2Thread = nil
        end
        loopSendPartOffset = CFrame.new()
        plistSendPartTarget = nil
        toggleBringPart(false)
    end
end
LoopSendPartV2Btn.MouseButton1Click:Connect(toggleLoopSendPartV2)

AntiLagBtn = createButton("", "Anti Lag")
antiLagActive = false
connections = {}
originalStates = {}
function safeSet(obj, prop, val)
    local success, current = pcall(function() return obj[prop] end)
    if success then
        if not originalStates[obj] then
            originalStates[obj] = {}
        end
        if originalStates[obj][prop] == nil then
            originalStates[obj][prop] = current
        end
        pcall(function() obj[prop] = val end)
    end
end
function makeBurik(v)
    if not antiLagActive then return end
    pcall(function()
        if v:IsA("BasePart") then
            safeSet(v, "Material", Enum.Material.SmoothPlastic)
            safeSet(v, "Reflectance", 0)
            safeSet(v, "CastShadow", false)
            if v:IsA("MeshPart") then
                safeSet(v, "TextureID", "")
                safeSet(v, "RenderFidelity", Enum.RenderFidelity.Performance)
            end
        elseif v:IsA("Decal") or v:IsA("Texture") then
            safeSet(v, "Transparency", 1)
        elseif v:IsA("ParticleEmitter") or v:IsA("Trail") or v:IsA("Beam") then
            if v:IsA("ParticleEmitter") or v:IsA("Trail") then
                safeSet(v, "Lifetime", NumberRange.new(0))
            end
            safeSet(v, "Enabled", false)
        elseif v:IsA("Explosion") then
            safeSet(v, "BlastPressure", 1)
            safeSet(v, "BlastRadius", 1)
        elseif v:IsA("Fire") or v:IsA("Smoke") or v:IsA("Sparkles") or v:IsA("Highlight") or v:IsA("Clouds") then
            safeSet(v, "Enabled", false)
        elseif v:IsA("Sound") then
            safeSet(v, "Playing", false)
        elseif v:IsA("Light") then
            safeSet(v, "Enabled", false)
        elseif v:IsA("SpecialMesh") then
            safeSet(v, "TextureId", "")
        elseif v:IsA("PostEffect") then
            safeSet(v, "Enabled", false)
        elseif v:IsA("Atmosphere") then
            safeSet(v, "Density", 0)
        elseif v:IsA("Shirt") then
            safeSet(v, "ShirtTemplate", "")
        elseif v:IsA("Pants") then
            safeSet(v, "PantsTemplate", "")
        elseif v:IsA("ShirtGraphic") then
            safeSet(v, "Graphic", "")
        end
    end)
end
function applyAntiLag()
    local l = game.Lighting
    local t = game.Workspace.Terrain
    local function lockLightingAndTerrain()
        safeSet(t, "WaterWaveSize", 0)
        safeSet(t, "WaterWaveSpeed", 0)
        safeSet(t, "WaterReflectance", 0)
        safeSet(t, "WaterTransparency", 0)
        safeSet(t, "Decoration", false)
        safeSet(l, "GlobalShadows", false)
        safeSet(l, "FogEnd", 9e9)
        safeSet(l, "Brightness", 0)
    end
    lockLightingAndTerrain()
    pcall(function()
        settings().Rendering.QualityLevel = Enum.QualityLevel.Level01
    end)
    if setfpscap then
        pcall(function() setfpscap(999) end)
    end
    task.spawn(function()
        local targets = {}
        for _, v in ipairs(workspace:GetDescendants()) do
            table.insert(targets, v)
        end
        for _, v in ipairs(l:GetDescendants()) do
            table.insert(targets, v)
        end
        local count = 0
        for _, v in ipairs(targets) do
            if not antiLagActive then break end
            makeBurik(v)
            count = count + 1
            if count % 300 == 0 then
                task.wait()
            end
        end
    end)
    connections[#connections+1] = workspace.DescendantAdded:Connect(function(obj)
        if antiLagActive then
            task.wait(0.1)
            if antiLagActive then
                makeBurik(obj)
            end
        end
    end)
    connections[#connections+1] = l.DescendantAdded:Connect(function(obj)
        if antiLagActive then
            task.wait(0.1)
            if antiLagActive then
                makeBurik(obj)
            end
        end
    end)
    connections[#connections+1] = l.Changed:Connect(function()
        if antiLagActive then
            lockLightingAndTerrain()
        end
    end)
    connections[#connections+1] = t.Changed:Connect(function()
        if antiLagActive then
            lockLightingAndTerrain()
        end
    end)
end
function resetAntiLag()
    for obj, state in pairs(originalStates) do
        if obj and obj.Parent then
            for prop, val in pairs(state) do
                pcall(function()
                    obj[prop] = val
                end)
            end
        end
    end
    originalStates = {}
    for _, c in pairs(connections) do
        c:Disconnect()
    end
    connections = {}
    if setfpscap then
        pcall(function() setfpscap(60) end)
    end
end
function toggleAntiLag(state)
    if state == nil then
        antiLagActive = not antiLagActive
    else
        antiLagActive = state
    end
    if antiLagActive then
        setButtonActive(AntiLagBtn, true)
        applyAntiLag()
    else
        setButtonActive(AntiLagBtn, false)
        resetAntiLag()
    end
end
AntiLagBtn.MouseButton1Click:Connect(function()
    toggleAntiLag()
end)
BToolsBtn = createButton("", "BTools")
BToolsBtn.Name = "BToolsBtn"
BToolsActive = false
function toggleBTools()
    local backpack = Player:FindFirstChildOfClass("Backpack")
    local char = Player.Character
    local found = false
    local function cleanTools(parent)
        if not parent then return end
        for _, item in ipairs(parent:GetChildren()) do
            if item:IsA("HopperBin") then
                pcall(function() item:Destroy() end)
                found = true
            end
        end
    end
    cleanTools(backpack)
    cleanTools(char)
    if found then
        BToolsActive = false
        setButtonActive(BToolsBtn, false)
        pcall(function()
            game:GetService("StarterGui"):SetCore("SendNotification", {
                Title = "BTools",
                Text = "Dihapus dari inventory",
                Duration = 3
            })
        end)
    else
        BToolsActive = true
        setButtonActive(BToolsBtn, true)
        pcall(function()
            -- Give standard HopperBin tools
            for i = 1, 4 do
                local tool = Instance.new("HopperBin")
                tool.BinType = i
                tool.Parent = backpack
            end
            
            -- Also give F3X (from Infinite Yield)
            task.spawn(function()
                local success, err = pcall(function()
                    loadstring(game:HttpGet("https://raw.githubusercontent.com/bochilascript/ROBLOX/refs/heads/main/f3x.lua"))()
                end)
                if not success then
                    warn("[CIT] Failed to load F3X: " .. tostring(err))
                end
            end)
            
            game:GetService("StarterGui"):SetCore("SendNotification", {
                Title = "BTools & F3X",
                Text = "BTools dan F3X diberikan!",
                Duration = 3
            })
        end)
    end
end
BToolsBtn.MouseButton1Click:Connect(toggleBTools)

