    DARK_BLUE = Color3.fromRGB(15, 15, 15),
    MEDIUM_BLUE = Color3.fromRGB(25, 25, 25),
    LIGHT_BLUE = Color3.fromRGB(255, 255, 255),
    NEON_BLUE = Color3.fromRGB(255, 50, 50),
    DARK_BLACK = Color3.fromRGB(5, 5, 5),
