        else
            if invisibleLoop then
                invisibleLoop:Disconnect()
                invisibleLoop = nil
                if Player.Character then
                    for _, v in ipairs(Player.Character:GetDescendants()) do
                        if v:IsA("BasePart") or v:IsA("Decal") then
                            if v.Name ~= "HumanoidRootPart" then
